(window.webpackJsonp=window.webpackJsonp||[]).push([[830],{790:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">salary</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> average = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">salary</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> max=-<span class=\\"hljs-literal\\">Infinity</span>,min=<span class=\\"hljs-literal\\">Infinity</span>\\n    <span class=\\"hljs-keyword\\">let</span> sum=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;salary.length;i++){\\n        max=<span class=\\"hljs-built_in\\">Math</span>.max(max,salary[i])\\n        min=<span class=\\"hljs-built_in\\">Math</span>.min(min,salary[i])\\n        sum+=salary[i]\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> (sum-max-min) / (salary.length<span class=\\"hljs-number\\">-2</span>)\\n};\\n</code></pre>\\n"],"titleSlug":"average-salary-excluding-the-minimum-and-maximum-salary","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4&nbsp;<code>salary</code>&nbsp;\uff0c\u6570\u7ec4\u91cc\u6bcf\u4e2a\u6570\u90fd\u662f <strong>\u552f\u4e00</strong>&nbsp;\u7684\uff0c\u5176\u4e2d&nbsp;<code>salary[i]</code> \u662f\u7b2c&nbsp;<code>i</code>&nbsp;\u4e2a\u5458\u5de5\u7684\u5de5\u8d44\u3002</p>\\n\\n<p>\u8bf7\u4f60\u8fd4\u56de\u53bb\u6389\u6700\u4f4e\u5de5\u8d44\u548c\u6700\u9ad8\u5de5\u8d44\u4ee5\u540e\uff0c\u5269\u4e0b\u5458\u5de5\u5de5\u8d44\u7684\u5e73\u5747\u503c\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>salary = [4000,3000,1000,2000]\\n<strong>\u8f93\u51fa\uff1a</strong>2500.00000\\n<strong>\u89e3\u91ca\uff1a</strong>\u6700\u4f4e\u5de5\u8d44\u548c\u6700\u9ad8\u5de5\u8d44\u5206\u522b\u662f 1000 \u548c 4000 \u3002\\n\u53bb\u6389\u6700\u4f4e\u5de5\u8d44\u548c\u6700\u9ad8\u5de5\u8d44\u4ee5\u540e\u7684\u5e73\u5747\u5de5\u8d44\u662f (2000+3000)/2= 2500\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>salary = [1000,2000,3000]\\n<strong>\u8f93\u51fa\uff1a</strong>2000.00000\\n<strong>\u89e3\u91ca\uff1a</strong>\u6700\u4f4e\u5de5\u8d44\u548c\u6700\u9ad8\u5de5\u8d44\u5206\u522b\u662f 1000 \u548c 3000 \u3002\\n\u53bb\u6389\u6700\u4f4e\u5de5\u8d44\u548c\u6700\u9ad8\u5de5\u8d44\u4ee5\u540e\u7684\u5e73\u5747\u5de5\u8d44\u662f (2000)/1= 2000\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>salary = [6000,5000,4000,3000,2000,1000]\\n<strong>\u8f93\u51fa\uff1a</strong>3500.00000\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>salary = [8000,9000,2000,3000,6000,1000]\\n<strong>\u8f93\u51fa\uff1a</strong>4750.00000\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>3 &lt;= salary.length &lt;= 100</code></li>\\n\\t<li><code>10^3&nbsp;&lt;= salary[i] &lt;= 10^6</code></li>\\n\\t<li><code>salary[i]</code>&nbsp;\u662f\u552f\u4e00\u7684\u3002</li>\\n\\t<li>\u4e0e\u771f\u5b9e\u503c\u8bef\u5dee\u5728&nbsp;<code>10^-5</code> \u4ee5\u5185\u7684\u7ed3\u679c\u90fd\u5c06\u89c6\u4e3a\u6b63\u786e\u7b54\u6848\u3002</li>\\n</ul>\\n","title":"1491. \u53bb\u6389\u6700\u4f4e\u5de5\u8d44\u548c\u6700\u9ad8\u5de5\u8d44\u540e\u7684\u5de5\u8d44\u5e73\u5747\u503c","relatedTags":["\u6392\u5e8f","\u6570\u7ec4"],"difficult":"Easy","lang":["javascript"],"uniqueID":"1491"}')}}]);